import React from "react";
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import NavBar from "../home-page/components/navbar";
import Carousel from "../home-page/components/carousel";
import Footer from "../home-page/components/footer";
import UserProfile from "../profile/components/user-profile";
import Collection from '../Collection/components/CollectionBody';
import Author from '../Authority/components/AuthorBody';
import Login from '../Login/components/loginPage';
import "../../index.css";
import "bootstrap/dist/css/bootstrap.min.css";
import "bootstrap-icons/font/bootstrap-icons.css";

function HomePage() {
  return (
    <>
      <NavBar />
      <Carousel />
      <Footer />
    </>
  );
}

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/login" element={<Login />} />
        <Route path="/" element={<HomePage />} />
        <Route
          path="/profile"
          element={
            <>
              <NavBar />
              <UserProfile />
              <Footer />
            </>
          }
        />
        <Route
          path="/collection"
          element={
            <>
              <NavBar />
              <Collection />
              <Footer />
            </>
          }
        />
        <Route
          path="/authority"
          element={
            <>
              <NavBar />
              <Author />
              <Footer />
            </>
          }
        />
        <Route path="*" element={<Navigate to="/" />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
